module RefModule(
    input A,
    input B,
    input SEL,
    output X
);wire not_sel;
    wire and1, and2;
    wire or1;

    assign not_sel = ~SEL;
  wire temp1_A = A;
  wire temp2_not_sel = not_sel;
  assign and1 = temp1_A & temp2_not_sel;
    assign and2 = B & SEL;
    assign or1 = and1 | and2;
    assign X = or1;

endmodule
